const ERC2981 = '0x2a55205a';

const is2981 = await client.readContract({
  address: collection, abi: NFT_ABI, functionName: 'supportsInterface', args: [ERC2981]
});
if (!is2981) throw new Error('Collection does not implement EIP-2981');

const [receiver, royaltyAmount] = await client.readContract({
  address: collection, abi: NFT_ABI, functionName: 'royaltyInfo',
  args: [tokenId, salePrice]
});

// Execute sale atomically (e.g., via marketplace contract that respects 2981)
await wallet.sendTransaction({
  to: marketplace, data: encodeFunctionData({
    abi: MARKETPLACE_ABI, functionName: 'sellWithRoyalty',
    args: [collection, tokenId, buyer, salePrice, receiver, royaltyAmount]
  })
});
